//! Runtime admission guard for Sardis-mode labels and vacuous truth cues.
//!
//! The guard separates an inference artifact from language that merely has the
//! shape of evidence. A true sentence with no task-bearing information can be
//! tempting to reuse in an LLM pipeline, but it must not settle admission.

use serde::{Deserialize, Serialize};

pub const SARDIS_GUARD_THEOREM: &str =
    "Gnosis.SardisDistributedIntelligenceGuard.distributed_intelligence_sardis_guard_bundle";

#[derive(Clone, Copy, Debug, Deserialize, Eq, PartialEq, Serialize)]
#[serde(rename_all = "camelCase")]
pub enum SardisClaimLabel {
    DistributedInference,
    DistributedIntelligence,
    RuntimeInferenceResult,
    GeneralTextClaim,
}

#[derive(Clone, Copy, Debug, Deserialize, Eq, PartialEq, Serialize)]
#[serde(rename_all = "camelCase")]
pub enum TruthCueClass {
    UsefulEvidence,
    VeridicalSway,
    VacuousTruth,
    PhantomBullshit,
}

#[derive(Clone, Copy, Debug, Deserialize, Eq, PartialEq, Serialize)]
#[serde(rename_all = "camelCase")]
pub enum SardisGuardVerdict {
    Admit,
    Reject,
}

#[derive(Clone, Debug, Deserialize, Eq, PartialEq, Serialize)]
#[serde(rename_all = "camelCase")]
pub struct TruthCueEvidence {
    #[serde(default)]
    pub tracks_truth: bool,
    #[serde(default)]
    pub adds_task_information: bool,
    #[serde(default)]
    pub speaker_truth_indifferent: bool,
    #[serde(default)]
    pub receiver_supplies_standing_wave: bool,
    #[serde(default)]
    pub has_live_measurement: bool,
    #[serde(default)]
    pub has_closure_certificate: bool,
}

#[derive(Clone, Debug, Deserialize, Eq, PartialEq, Serialize)]
#[serde(rename_all = "camelCase")]
pub struct SardisGuardInput {
    pub claim_label: SardisClaimLabel,
    pub live_carrier_count: u32,
    pub required_carrier_count: u32,
    pub task_information_bits: u32,
    pub truth_cue: TruthCueEvidence,
}

#[derive(Clone, Debug, Deserialize, Eq, PartialEq, Serialize)]
#[serde(rename_all = "camelCase")]
pub struct SardisGuardReport {
    pub theorem: String,
    pub claim_label: SardisClaimLabel,
    pub cue_class: TruthCueClass,
    pub verdict: SardisGuardVerdict,
    pub admitted: bool,
    pub live_carrier_count: u32,
    pub required_carrier_count: u32,
    pub task_information_bits: u32,
    pub reason: String,
    pub obligation: Option<String>,
}

pub fn classify_truth_cue(cue: &TruthCueEvidence) -> TruthCueClass {
    if cue.speaker_truth_indifferent {
        return TruthCueClass::PhantomBullshit;
    }
    if cue.adds_task_information && (cue.has_live_measurement || cue.has_closure_certificate) {
        return TruthCueClass::UsefulEvidence;
    }
    if cue.tracks_truth && !cue.adds_task_information && cue.receiver_supplies_standing_wave {
        return TruthCueClass::VeridicalSway;
    }
    if cue.tracks_truth && !cue.adds_task_information {
        return TruthCueClass::VacuousTruth;
    }
    TruthCueClass::PhantomBullshit
}

pub fn admit_sardis_claim(input: SardisGuardInput) -> SardisGuardReport {
    let cue_class = classify_truth_cue(&input.truth_cue);
    let carrier_admitted = input.live_carrier_count >= input.required_carrier_count;
    let useful = cue_class == TruthCueClass::UsefulEvidence && input.task_information_bits > 0;
    let admitted = match input.claim_label {
        SardisClaimLabel::DistributedInference | SardisClaimLabel::RuntimeInferenceResult => {
            carrier_admitted && useful
        }
        SardisClaimLabel::DistributedIntelligence => {
            carrier_admitted && useful && input.required_carrier_count > 1
        }
        SardisClaimLabel::GeneralTextClaim => false,
    };
    let (reason, obligation) = sardis_reason(&input, cue_class, admitted, carrier_admitted, useful);

    SardisGuardReport {
        theorem: SARDIS_GUARD_THEOREM.to_string(),
        claim_label: input.claim_label,
        cue_class,
        verdict: if admitted {
            SardisGuardVerdict::Admit
        } else {
            SardisGuardVerdict::Reject
        },
        admitted,
        live_carrier_count: input.live_carrier_count,
        required_carrier_count: input.required_carrier_count,
        task_information_bits: input.task_information_bits,
        reason,
        obligation,
    }
}

pub fn generation_sardis_guard(
    prompt_token_count: u32,
    generated_token_count: u32,
    has_workflow_certificate: bool,
) -> SardisGuardReport {
    let task_information_bits = generated_token_count.saturating_mul(32);
    admit_sardis_claim(SardisGuardInput {
        claim_label: SardisClaimLabel::RuntimeInferenceResult,
        live_carrier_count: u32::from(has_workflow_certificate && generated_token_count > 0),
        required_carrier_count: 1,
        task_information_bits,
        truth_cue: TruthCueEvidence {
            tracks_truth: false,
            adds_task_information: prompt_token_count > 0 && generated_token_count > 0,
            speaker_truth_indifferent: false,
            receiver_supplies_standing_wave: false,
            has_live_measurement: generated_token_count > 0,
            has_closure_certificate: has_workflow_certificate,
        },
    })
}

fn sardis_reason(
    input: &SardisGuardInput,
    cue_class: TruthCueClass,
    admitted: bool,
    carrier_admitted: bool,
    useful: bool,
) -> (String, Option<String>) {
    if admitted {
        return (
            "claim admitted as a task-bearing runtime artifact, not as semantic authority"
                .to_string(),
            None,
        );
    }
    if !carrier_admitted {
        return (
            format!(
                "claim label requires {} live carrier(s), observed {}",
                input.required_carrier_count, input.live_carrier_count
            ),
            Some("lower the label or attach live carrier evidence before admission".to_string()),
        );
    }
    if !useful {
        return match cue_class {
            TruthCueClass::VeridicalSway => (
                "truth cue can stabilize a receiver standing wave but adds no task information"
                    .to_string(),
                Some(
                    "treat as veridical sway; require a measurement or closure certificate"
                        .to_string(),
                ),
            ),
            TruthCueClass::VacuousTruth => (
                "truth cue tracks truth but carries no task-bearing information".to_string(),
                Some("do not use vacuous truth as inference evidence".to_string()),
            ),
            TruthCueClass::PhantomBullshit => (
                "cue is indifferent to truth or lacks admissible information".to_string(),
                Some("route to audit or rejection, not inference reuse".to_string()),
            ),
            TruthCueClass::UsefulEvidence => (
                "useful evidence cue lacks positive task information bits".to_string(),
                Some("attach task-bearing payload before admission".to_string()),
            ),
        };
    }
    (
        "claim label outruns its admitted runtime role".to_string(),
        Some("keep this at distributed-inference scope until stronger carriers exist".to_string()),
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    fn useful_input(label: SardisClaimLabel) -> SardisGuardInput {
        SardisGuardInput {
            claim_label: label,
            live_carrier_count: 1,
            required_carrier_count: 1,
            task_information_bits: 64,
            truth_cue: TruthCueEvidence {
                tracks_truth: false,
                adds_task_information: true,
                speaker_truth_indifferent: false,
                receiver_supplies_standing_wave: false,
                has_live_measurement: true,
                has_closure_certificate: true,
            },
        }
    }

    #[test]
    fn distributed_inference_label_is_admitted_with_live_evidence() {
        let report = admit_sardis_claim(useful_input(SardisClaimLabel::DistributedInference));
        assert!(report.admitted);
        assert_eq!(report.verdict, SardisGuardVerdict::Admit);
        assert_eq!(report.cue_class, TruthCueClass::UsefulEvidence);
    }

    #[test]
    fn distributed_intelligence_label_rejected_when_label_outruns_carrier() {
        let report = admit_sardis_claim(useful_input(SardisClaimLabel::DistributedIntelligence));
        assert!(!report.admitted);
        assert_eq!(report.verdict, SardisGuardVerdict::Reject);
        assert!(report
            .obligation
            .as_deref()
            .unwrap_or_default()
            .contains("distributed-inference"));
    }

    #[test]
    fn vacuous_truth_is_rejected_without_task_information() {
        let report = admit_sardis_claim(SardisGuardInput {
            claim_label: SardisClaimLabel::DistributedInference,
            live_carrier_count: 1,
            required_carrier_count: 1,
            task_information_bits: 0,
            truth_cue: TruthCueEvidence {
                tracks_truth: true,
                adds_task_information: false,
                speaker_truth_indifferent: false,
                receiver_supplies_standing_wave: false,
                has_live_measurement: false,
                has_closure_certificate: true,
            },
        });
        assert!(!report.admitted);
        assert_eq!(report.cue_class, TruthCueClass::VacuousTruth);
        assert!(report.reason.contains("no task-bearing information"));
    }

    #[test]
    fn veridical_sway_is_not_admission_evidence() {
        let report = admit_sardis_claim(SardisGuardInput {
            claim_label: SardisClaimLabel::DistributedInference,
            live_carrier_count: 1,
            required_carrier_count: 1,
            task_information_bits: 0,
            truth_cue: TruthCueEvidence {
                tracks_truth: true,
                adds_task_information: false,
                speaker_truth_indifferent: false,
                receiver_supplies_standing_wave: true,
                has_live_measurement: false,
                has_closure_certificate: true,
            },
        });
        assert!(!report.admitted);
        assert_eq!(report.cue_class, TruthCueClass::VeridicalSway);
        assert!(report.reason.contains("standing wave"));
    }

    #[test]
    fn generation_guard_admits_nonempty_certificate_bearing_artifact() {
        let report = generation_sardis_guard(3, 2, true);
        assert!(report.admitted);
        assert_eq!(report.claim_label, SardisClaimLabel::RuntimeInferenceResult);
        assert_eq!(report.task_information_bits, 64);
    }

    #[test]
    fn generation_guard_rejects_empty_completion() {
        let report = generation_sardis_guard(3, 0, true);
        assert!(!report.admitted);
        assert_eq!(report.live_carrier_count, 0);
    }
}
